#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 10

void backtrack(int* lis, int n, char* result, int index) {
    if (index == n) {
        printf("%s\n", result);
        return;
    }
    for (int i = 1; i <= 9; i++) {
        if (index == 0 || (result[index - 1] - '0') < i) {
            if (lis[index] == 1 || lis[index] == lis[index - 1] + 1) {
                result[index] = i + '0';
                result[index + 1] = '\0';
                backtrack(lis, n, result, index + 1);
            }
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int* lis = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &lis[i]);
        }
        char* result = (char*)malloc((n + 1) * sizeof(char));
        result[0] = '\0';
        backtrack(lis, n, result, 0);
        free(lis);
        free(result);
    }
    return 0;
}

