import java.util.Scanner;
public class Main {
    public static void backtrack(int[] lis, int n, StringBuilder result, int index) {
        if (index == n) {
            System.out.println(result.toString());
            return;
        }
        for (int i = 1; i <= 9; i++) {
            if (index == 0 || (result.charAt(index - 1) - '0') < i) {
                if (lis[index] == 1 || lis[index] == lis[index - 1] + 1) {
                    result.append(String.valueOf(i));
                    backtrack(lis, n, result, index + 1);
                    result.deleteCharAt(result.length() - 1);
                }
            }
        }
    }
